  `year` int(11) DEFAULT NULL,
  `month` int(11) DEFAULT NULL,
  `period` varchar(7) DEFAULT NULL,
  `observed_on` date DEFAULT NULL,
  `region` varchar(255) DEFAULT NULL,
  `district` varchar(255) DEFAULT NULL,
  `survey_area` varchar(255) DEFAULT NULL,
  `area_code` varchar(32) DEFAULT NULL,
  `map_url` varchar(512) DEFAULT NULL,
  `x` double DEFAULT NULL,
  `y` double DEFAULT NULL,
  `agi_percent` double DEFAULT NULL,
  `adi` double DEFAULT NULL,
  `is_partial` tinyint(1) DEFAULT 0,
  `source_document` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_fehd_period` (`observed_on`),
  KEY `idx_fehd_area` (`survey_area`),
  KEY `idx_fehd_district` (`district`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

